function getKey(offset = 0) {
  const d = new Date(); d.setDate(d.getDate() - offset);
  return d.toISOString().split("T")[0];
}
function fmtMins(m) {
  if (!m || m <= 0) return "0m";
  if (m < 60) return `${m}m`;
  return `${Math.floor(m / 60)}h${m % 60 ? " " + (m % 60) + "m" : ""}`;
}
