  const iv=useRef(null);
  useEffect(()=>{if(running)iv.current=setInterval(()=>setSecs(s=>{if(s<=1){setRunning(false);const nx=mode==="focus"?"break":"focus";setMode(nx);return nx==="focus"?25*60:5*60;}return s-1;}),1000);else clearInterval(iv.current);return()=>clearInterval(iv.current);},[running,mode]);
  const pct=mode==="focus"?(1-secs/(25*60))*100:(1-secs/(5*60))*100,mm=String(Math.floor(secs/60)).padStart(2,"0"),ss=String(secs%60).padStart(2,"0");
